import { afterEach, beforeEach, describe, expect, it } from "vitest";
import { setSyncedStateClientForTesting, } from "../client";
import { createSyncedStateHook, } from "../useSyncedState";
const createStateHarness = () => {
    let currentState;
    const cleanups = [];
    const useStateImpl = ((initialValue) => {
        const resolved = typeof initialValue === "function"
            ? initialValue()
            : initialValue;
        currentState = resolved;
        const setState = (next) => {
            currentState =
                typeof next === "function"
                    ? next(currentState)
                    : next;
        };
        return [currentState, setState];
    });
    const useEffectImpl = (callback) => {
        const cleanup = callback();
        if (typeof cleanup === "function") {
            cleanups.push(cleanup);
        }
    };
    const useRefImpl = ((value) => ({
        current: value,
    }));
    const useCallbackImpl = (fn) => fn;
    const deps = {
        useState: useStateImpl,
        useEffect: useEffectImpl,
        useRef: useRefImpl,
        useCallback: useCallbackImpl,
    };
    return {
        deps,
        getState: () => currentState,
        runCleanups: () => cleanups.forEach((fn) => fn()),
    };
};
describe("createSyncedStateHook", () => {
    const subscribeHandlers = new Map();
    const client = {
        async getState() {
            return 5;
        },
        async setState(_value, _key) { },
        async subscribe(key, handler) {
            subscribeHandlers.set(key, handler);
        },
        async unsubscribe(key) {
            subscribeHandlers.delete(key);
        },
    };
    const resetClient = () => {
        client.getState = async () => 5;
        client.setState = async (_value, _key) => { };
        client.subscribe = async (key, handler) => {
            subscribeHandlers.set(key, handler);
        };
        client.unsubscribe = async (key) => {
            subscribeHandlers.delete(key);
        };
    };
    beforeEach(() => {
        resetClient();
        setSyncedStateClientForTesting(client);
        subscribeHandlers.clear();
    });
    afterEach(() => {
        setSyncedStateClientForTesting(null);
    });
    it("loads remote state and updates local value", async () => {
        const harness = createStateHarness();
        const useSyncedState = createSyncedStateHook({ hooks: harness.deps });
        const [value] = useSyncedState(0, "counter");
        expect(value).toBe(0);
        await Promise.resolve();
        expect(harness.getState()).toBe(5);
    });
    it("sends updates through the client and applies optimistic value", async () => {
        const harness = createStateHarness();
        const setCalls = [];
        client.setState = async (value, key) => {
            setCalls.push({ key, value });
        };
        const useSyncedState = createSyncedStateHook({ hooks: harness.deps });
        const [, setSyncValue] = useSyncedState(0, "counter");
        setSyncValue(9);
        expect(harness.getState()).toBe(9);
        expect(setCalls).toEqual([{ key: "counter", value: 9 }]);
    });
    it("applies remote updates from the subscription handler", async () => {
        const harness = createStateHarness();
        const useSyncedState = createSyncedStateHook({ hooks: harness.deps });
        useSyncedState(0, "counter");
        await Promise.resolve();
        const handler = subscribeHandlers.get("counter");
        handler?.(7);
        expect(harness.getState()).toBe(7);
    });
    it("unsubscribes during cleanup", () => {
        const harness = createStateHarness();
        const unsubscribed = [];
        client.unsubscribe = async (key) => {
            unsubscribed.push({ key });
            subscribeHandlers.delete(key);
        };
        const useSyncedState = createSyncedStateHook({ hooks: harness.deps });
        useSyncedState(0, "counter");
        harness.runCleanups();
        expect(unsubscribed).toEqual([{ key: "counter" }]);
    });
});

import React from "react";
import { describe, expect, it } from "vitest";
import { defineRoutes, except, index, layout, matchPath, prefix, render, route, } from "./router";
describe("matchPath", () => {
    // Test case 1: Static paths
    it("should match static paths", () => {
        expect(matchPath("/about/", "/about/")).toEqual({});
        expect(matchPath("/contact/", "/contact/")).toEqual({});
    });
    it("should not match different static paths", () => {
        expect(matchPath("/about/", "/service/")).toBeNull();
    });
    // Test case 2: Paths with parameters
    it("should match paths with parameters and extract them", () => {
        expect(matchPath("/users/:id/", "/users/123/")).toEqual({ id: "123" });
        expect(matchPath("/posts/:category/:slug/", "/posts/tech/my-first-post/")).toEqual({ category: "tech", slug: "my-first-post" });
    });
    it("should not match if parameter is missing", () => {
        expect(matchPath("/users/:id/", "/users/")).toBeNull();
    });
    // Test case 3: Paths with wildcards
    it("should match paths with wildcards and extract them", () => {
        expect(matchPath("/files/*/", "/files/document.pdf/")).toEqual({
            $0: "document.pdf",
        });
        expect(matchPath("/data/*/content/", "/data/archive/content/")).toEqual({
            $0: "archive",
        });
        expect(matchPath("/assets/*/*/", "/assets/images/pic.png/")).toEqual({
            $0: "images",
            $1: "pic.png",
        });
    });
    it("should match empty wildcard", () => {
        expect(matchPath("/files/*/", "/files//")).toEqual({ $0: "" });
    });
    it("should match wildcard route against root path", () => {
        // Wildcard route should match the root path "/"
        // This tests the regression where route("*") stopped matching "/"
        expect(matchPath("/*", "/")).toEqual({ $0: "" });
    });
    // Test case 4: Paths with both parameters and wildcards
    it("should match paths with both parameters and wildcards", () => {
        expect(matchPath("/products/:productId/*/", "/products/abc/details/more/")).toEqual({ productId: "abc", $0: "details/more" });
    });
    // Test case 5: Paths that don't match
    it("should return null for non-matching paths", () => {
        expect(matchPath("/specific/path/", "/a/different/path/")).toBeNull();
    });
    // Test case 6: Edge cases
    it("should handle trailing slashes correctly", () => {
        // Current implementation in defineRoutes adds a trailing slash if missing,
        // and route() function also enforces it. matchPath itself doesn't normalize.
        expect(matchPath("/path/", "/path")).toBeNull(); // Path to match must end with /
        expect(matchPath("/path/", "/path/")).toEqual({});
    });
    it("should handle paths with multiple parameters and wildcards interspersed", () => {
        expect(matchPath("/type/:typeId/item/*/:itemId/*/", "/type/a/item/image/b/thumb/")).toEqual({ typeId: "a", $0: "image", itemId: "b", $1: "thumb" });
    });
    it("should not allow named parameters or wildcards in the same path", () => {
        expect(() => matchPath("/type/:typeId:is:broken", "/type/a-thumb-drive")).toThrow();
        expect(() => matchPath("/type/**", "/type/a-thumb-drive")).toThrow();
    });
});
