import { render, route } from "rwsdk/router";
import { defineApp } from "rwsdk/worker";
import { SyncedStateServer, syncedStateRoutes } from "rwsdk/use-synced-state/worker";

import { Document } from "@/app/document";
import { setCommonHeaders } from "@/app/headers";
import { Home } from "@/app/pages/home";
import { Board } from "@/app/pages/board";

export type AppContext = {};

// Export SyncedStateServer as a Durable Object class so Wrangler can bind it.
export { SyncedStateServer };

// Register a room handler so each boardId maps to its own DO instance.
SyncedStateServer.registerRoomHandler(async (roomId) => {
  return roomId ?? "default-room";
});

export default defineApp([
  setCommonHeaders(),
  ({ ctx }) => {
    // setup ctx here
    ctx;
  },
  render(Document, [
    route("/", Home),
    route("/board/:boardId", ({ params }) => <Board boardId={params.boardId} />),
    // JSON API endpoint to read the current dot list for a board.
    // This reaches directly into the Durable Object to get state.
    route("/api/board/:boardId", {
      get: async ({ params, env }) => {
        const id = env.SYNCED_STATE.idFromName(params.boardId);
        const stub = env.SYNCED_STATE.get(id);
        const dots = (await stub.getState("dots")) ?? [];
        return Response.json({ dots }, {
          headers: { "Content-Type": "application/json" },
        });
      },
    }),
    // Synced state routes for WebSocket-based real-time sync
    ...syncedStateRoutes((env) => env.SYNCED_STATE),
  ]),
]);

import { BoardCanvas } from "./board-canvas";

export const Board = ({ boardId }: { boardId: string }) => {
  return (
    <div style={{ padding: "16px", fontFamily: "sans-serif" }}>
      <h1>Whiteboard: {boardId}</h1>
      <BoardCanvas boardId={boardId} />
    </div>
  );
};

"use client";

import { useSyncedState } from "rwsdk/use-synced-state/client";
import { useCallback, useEffect, useRef } from "react";

export interface Dot {
  x: number;
  y: number;
  color: string;
}

// A palette of deterministic colors, picked based on the dot index.
const COLORS = [
  "#e6194b",
  "#3cb44b",
  "#ffe119",
  "#4363d8",
  "#f58231",
  "#911eb4",
  "#42d4f4",
  "#f032e6",
  "#bfef45",
  "#fabed4",
  "#469990",
  "#dcbeff",
  "#9a6324",
  "#fffac8",
  "#800000",
  "#aaffc3",
  "#808000",
  "#ffd8b1",
  "#000075",
  "#a9a9a9",
];

function colorForIndex(index: number): string {
  return COLORS[index % COLORS.length];
}

export const BoardCanvas = ({ boardId }: { boardId: string }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const [dots, setDots] = useSyncedState<Dot[]>(
    [] as Dot[],
    "dots",
    boardId,
  );

  // Redraw canvas whenever dots change
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    // Resize canvas to match its display size for sharp rendering
    const rect = canvas.getBoundingClientRect();
    canvas.width = rect.width;
    canvas.height = rect.height;

    // Clear and redraw all dots
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    for (const dot of dots) {
      ctx.beginPath();
      ctx.arc(dot.x, dot.y, 6, 0, 2 * Math.PI);
      ctx.fillStyle = dot.color;
      ctx.fill();
    }
  }, [dots]);

  const handleCanvasClick = useCallback(
    (e: React.MouseEvent<HTMLCanvasElement>) => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const rect = canvas.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;
      const newDot: Dot = {
        x: Math.round(x),
        y: Math.round(y),
        color: colorForIndex(dots.length),
      };
      setDots([...dots, newDot]);
    },
    [dots, setDots],
  );

  const handleClear = useCallback(() => {
    setDots([]);
  }, [setDots]);

  return (
    <div>
      <canvas
        ref={canvasRef}
        onClick={handleCanvasClick}
        style={{
          border: "2px solid #333",
          borderRadius: "4px",
          cursor: "crosshair",
          display: "block",
          width: "100%",
          maxWidth: "800px",
          height: "500px",
          backgroundColor: "#fff",
        }}
      />
      <button
        onClick={handleClear}
        style={{
          marginTop: "12px",
          padding: "8px 20px",
          fontSize: "16px",
          cursor: "pointer",
        }}
      >
        Clear
      </button>
    </div>
  );
};
